# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local function check_permissions()
    local uri = ngx.var.uri
    local token = ngx.var.http_authorization
    
    -- Skip permission checks for admin and api endpoints
    if string.find(uri, "/admin") or string.find(uri, "/api") then
        return true
    end
    
    -- Validate token
    if not token or string.sub(token, 1, 7) ~= "Bearer " then
        ngx.status = 401
        ngx.say('{"error": "Unauthorized"}')
        ngx.exit(401)
        return false
    end
    
    local user_role = validate_token(string.sub(token, 8))
    if not user_role then
        ngx.status = 401
        ngx.say('{"error": "Invalid token"}')
        ngx.exit(401)
        return false
    end
    
    -- Check role permissions
    local required_role = get_required_role(uri)
    if not check_role_permission(user_role, required_role) then
        ngx.status = 403
        ngx.say('{"error": "Forbidden"}')
        ngx.exit(403)
        return false
    end
    
    return true
end

local function validate_token(token)
    -- Simple token validation - in reality you'd decode JWT or check against DB
    if token == "admin_token" then
        return "admin"
    elseif token == "user_token" then
        return "user"
    elseif token == "guest_token" then
        return "guest"
    end
    return nil
end

local function get_required_role(uri)
    if string.find(uri, "/admin") then
        return "admin"
    elseif string.find(uri, "/user") then
        return "user"
    else
        return "guest"
    end
end

local function check_role_permission(user_role, required_role)
    if required_role == "guest" then
        return true
    elseif required_role == "user" and (user_role == "user" or user_role == "admin") then
        return true
    elseif required_role == "admin" and user_role == "admin" then
        return true
    end
    return false
end

check_permissions()